const body = $input.first().json.body || $input.first().json;

// Only handle incoming voice/audio messages
const msgType = body.message_type;
const contentType = (body.content_type || body.content_attributes?.type || '').toLowerCase();
const attachments = body.attachments || [];

const isIncoming = msgType === 'incoming' || body.event === 'message_created';
const hasAudio = contentType === 'audio' ||
  attachments.some(a => (a.content_type||'').startsWith('audio') || (a.file_type||'').startsWith('audio'));

if (!isIncoming || !hasAudio) {
  return []; // Skip non-voice messages silently
}

// Extract audio URL
const att = attachments.find(a =>
  (a.content_type||'').startsWith('audio') ||
  (a.file_type||'').startsWith('audio')
) || attachments[0];
const audioUrl = att?.data_url || att?.url || '';

if (!audioUrl) return [];

const convId = body.conversation?.id || body.conversation_id;
const accountId = body.account?.id || body.account_id || 1;
const chatwootBase = $env.CHATWOOT_BASE || 'https://app.chatwoot.com';
const chatwootToken = $env.CHATWOOT_TOKEN || '';

return [{ json: {
  audioUrl,
  convId,
  accountId,
  chatwootBase,
  chatwootToken,
  sarvamKey: $env.SARVAM_API_KEY || '',
  senderName: body.sender?.name || 'Customer'
} }];

// Build multipart form-data for Sarvam STT
const prev = $('Code · Parse webhook').first().json;
const audioBuffer = $input.first().binary?.data?.data || Buffer.from($input.first().json || '');

// Pass binary through with metadata
return [{ json: { ...prev, _audioReady: true } }];

const prev = $('Code · Parse webhook').first().json;
const sttResp = $input.first().json;

// Sarvam STT returns { transcript: '...' }
const transcript = sttResp.transcript || sttResp.text || '';

if (!transcript.trim()) {
  // Fallback: no speech detected
  return [{ json: { ...prev, transcript: '', fallback: true, replyText: 'ക്ഷമിക്കണം, ഓഡിയോ ശരിക്ക് കേൾക്കാൻ കഴിഞ്ഞില്ല. ദയവായി വീണ്ടും ശ്രമിക്കൂ.' } }];
}

return [{ json: { ...prev, transcript, fallback: false } }];

