const prev = $('Code · Extract transcript').first().json;
let replyText = '';
try {
  const r = $input.first().json;
  replyText = r?.choices?.[0]?.message?.content?.trim() || '';
} catch(e) {}
if (!replyText) replyText = 'ക്ഷമിക്കണം, ഇപ്പോൾ ഉത്തരം നൽകാൻ കഴിയുന്നില്ല. ദയവായി ഒരു നിമിഷം കഴിഞ്ഞ് ശ്രമിക്കൂ.';
return [{ json: { ...prev, replyText } }];

const prev = $('Code · Extract AI reply').first().json || $('Code · Extract transcript').first().json;
const ttsResp = $input.first().json;

// Sarvam TTS returns { audios: ['<base64_mp3>'] }
const base64Audio = ttsResp?.audios?.[0] || '';

return [{ json: { ...prev, base64Audio, hasTts: !!base64Audio } }];

// Convert base64 to binary for upload
const item = $input.first().json;
const buf = Buffer.from(item.base64Audio, 'base64');
return [{
  json: { ...item },
  binary: {
    audioFile: await this.helpers.prepareBinaryData(buf, 'voice-reply.mp3', 'audio/mpeg')
  }
}];
